const amqp = require('amqplib');
const crypto = require('crypto');

// Configuration
const RABBITMQ_URL = process.env.RABBITMQ_URL || 'amqp://localhost';
const PAYMENT_QUEUE = 'payment_events';
const MESSAGE_SIGNING_SECRET = process.env.MESSAGE_SIGNING_SECRET;

if (!MESSAGE_SIGNING_SECRET) {
  console.error('FATAL: MESSAGE_SIGNING_SECRET environment variable is required.');
  console.error('Payment messages MUST be signed to prevent fraud.');
  process.exit(1);
}

// Verify HMAC signature on incoming messages
function verifyMessageSignature(messageBody, signature) {
  const expectedSignature = crypto
    .createHmac('sha256', MESSAGE_SIGNING_SECRET)
    .update(messageBody)
    .digest('hex');

  return crypto.timingSafeEqual(
    Buffer.from(signature, 'hex'),
    Buffer.from(expectedSignature, 'hex')
  );
}

// Validate payment event structure and content
function validatePaymentEvent(event) {
  const errors = [];

  if (!event || typeof event !== 'object') {
    return { valid: false, errors: ['Event must be a non-null object'] };
  }

  // Required fields
  const requiredFields = ['eventId', 'eventType', 'timestamp', 'paymentData'];
  for (const field of requiredFields) {
    if (!event[field]) {
      errors.push(`Missing required field: ${field}`);
    }
  }

  // Validate event type against allowlist
  const allowedEventTypes = [
    'payment.created',
    'payment.authorized',
    'payment.captured',
    'payment.refunded',
    'payment.failed',
  ];
  if (!allowedEventTypes.includes(event.eventType)) {
    errors.push(`Invalid event type: ${event.eventType}`);
  }

  // Validate timestamp is recent (within 5 minutes to prevent replay attacks)
  if (event.timestamp) {
    const eventTime = new Date(event.timestamp).getTime();
    const now = Date.now();
    const fiveMinutes = 5 * 60 * 1000;
    if (isNaN(eventTime) || Math.abs(now - eventTime) > fiveMinutes) {
      errors.push('Event timestamp is too old or invalid (possible replay attack)');
    }
  }

  // Validate payment data
  if (event.paymentData) {
    const { amount, currency, orderId } = event.paymentData;

    if (typeof amount !== 'number' || amount <= 0 || amount > 1000000) {
      errors.push('Invalid payment amount');
    }
    if (typeof currency !== 'string' || !/^[A-Z]{3}$/.test(currency)) {
      errors.push('Invalid currency code');
    }
    if (typeof orderId !== 'string' || !/^[a-zA-Z0-9\-]{1,64}$/.test(orderId)) {
      errors.push('Invalid order ID format');
    }
  }

  return { valid: errors.length === 0, errors };
}

// Idempotency tracking (use Redis or a database in production)
const processedEventIds = new Set();

function isAlreadyProcessed(eventId) {
  return processedEventIds.has(eventId);
}

function markAsProcessed(eventId) {
  processedEventIds.add(eventId);
  // In production, use Redis with TTL or a database table
}

// Payment processing handlers (safe, validated logic only)
const paymentHandlers = {
  'payment.created': async (paymentData) => {
    console.log(`[HANDLER] Processing new payment for order ${paymentData.orderId}, amount: ${paymentData.amount} ${paymentData.currency}`);
    // Call your payment gateway SDK here
    // e.g., await stripe.paymentIntents.create(...)
    return { status: 'created', orderId: paymentData.orderId };
  },

  'payment.authorized': async (paymentData) => {
    console.log(`[HANDLER] Payment authorized for order ${paymentData.orderId}`);
    // Update order status in database
    return { status: 'authorized', orderId: paymentData.orderId };
  },

  'payment.captured': async (paymentData) => {
    console.log(`[HANDLER] Payment captured for order ${paymentData.orderId}`);
    // Finalize the payment, update inventory, send confirmation
    return { status: 'captured', orderId: paymentData.orderId };
  },

  'payment.refunded': async (paymentData) => {
    console.log(`[HANDLER] Processing refund for order ${paymentData.orderId}`);
    // Process refund through payment gateway
    return { status: 'refunded', orderId: paymentData.orderId };
  },

  'payment.failed': async (paymentData) => {
    console.log(`[HANDLER] Payment failed for order ${paymentData.orderId}`);
    // Handle failure, notify customer, release inventory
    return { status: 'failed', orderId: paymentData.orderId };
  },
};

async function processMessage(msg, channel) {
  const rawContent = msg.content.toString();
  const signature = msg.properties.headers?.signature;

  // STEP 1: Verify message signature
  if (!signature) {
    console.error('[SECURITY] Message rejected: missing signature header');
    // Dead-letter the unsigned message for security review
    channel.nack(msg, false, false);
    return;
  }

  try {
    if (!verifyMessageSignature(rawContent, signature)) {
      console.error('[SECURITY] Message rejected: invalid signature (possible tampering)');
      channel.nack(msg, false, false);
      return;
    }
  } catch (err) {
    console.error('[SECURITY] Message rejected: signature verification error', err.message);
    channel.nack(msg, false, false);
    return;
  }

  // STEP 2: Parse message safely
  let event;
  try {
    event = JSON.parse(rawContent);
  } catch (err) {
    console.error('[PARSE] Message rejected: invalid JSON', err.message);
    channel.nack(msg, false, false);
    return;
  }

  // STEP 3: Validate message structure and content
  const validation = validatePaymentEvent(event);
  if (!validation.valid) {
    console.error('[VALIDATION] Message rejected:', validation.errors.join(', '));
    channel.nack(msg, false, false);
    return;
  }

  // STEP 4: Idempotency check
  if (isAlreadyProcessed(event.eventId)) {
    console.warn(`[IDEMPOTENCY] Event ${event.eventId} already processed, acknowledging duplicate`);
    channel.ack(msg);
    return;
  }

  // STEP 5: Process the payment event
  const handler = paymentHandlers[event.eventType];
  if (!handler) {
    console.error(`[HANDLER] No handler for event type: ${event.eventType}`);
    channel.nack(msg, false, false);
    return;
  }

  try {
    const result = await handler(event.paymentData);
    console.log(`[SUCCESS] Event ${event.eventId} processed:`, result);
    markAsProcessed(event.eventId);
    channel.ack(msg);
  } catch (err) {
    console.error(`[ERROR] Failed to process event ${event.eventId}:`, err.message);
    // Requeue for retry (with limits in production via dead-letter exchange)
    channel.nack(msg, false, true);
  }
}

async function startConsumer() {
  let connection;
  let channel;

  try {
    connection = await amqp.connect(RABBITMQ_URL);
    channel = await connection.createChannel();

    // Set up dead-letter exchange for rejected messages
    await channel.assertExchange('payment_dlx', 'direct', { durable: true });
    await channel.assertQueue('payment_dead_letter', {
      durable: true,
      arguments: { 'x-message-ttl': 86400000 }, // 24h TTL
    });
    await channel.bindQueue('payment_dead_letter', 'payment_dlx', PAYMENT_QUEUE);

    // Set up main payment queue with dead-lettering
    await channel.assertQueue(PAYMENT_QUEUE, {
      durable: true,
      arguments: {
        'x-dead-letter-exchange': 'payment_dlx',
        'x-dead-letter-routing-key': PAYMENT_QUEUE,
      },
    });

    // Prefetch 1 message at a time for safe processing
    await channel.prefetch(1);

    console.log(`[*] Waiting for payment events on queue: ${PAYMENT_QUEUE}`);
    console.log('[*] Message signature verification: ENABLED');
    console.log('[*] Input validation: ENABLED');
    console.log('[*] Idempotency checking: ENABLED');

    channel.consume(PAYMENT_QUEUE, (msg) => {
      if (msg !== null) {
        processMessage(msg, channel);
      }
    });

    // Graceful shutdown
    const shutdown = async (signal) => {
      console.log(`\n[${signal}] Shutting down gracefully...`);
      try {
        await channel.close();
        await connection.close();
      } catch (err) {
        console.error('Error during shutdown:', err.message);
      }
      process.exit(0);
    };

    process.on('SIGINT', () => shutdown('SIGINT'));
    process.on('SIGTERM', () => shutdown('SIGTERM'));

    connection.on('error', (err) => {
      console.error('[CONNECTION] RabbitMQ connection error:', err.message);
    });

    connection.on('close', () => {
      console.error('[CONNECTION] RabbitMQ connection closed, exiting...');
      process.exit(1);
    });
  } catch (err) {
    console.error('[FATAL] Failed to start consumer:', err.message);
    process.exit(1);
  }
}

// --- Utility: Example publisher with signing (for testing) ---
async function publishSignedMessage(event) {
  const connection = await amqp.connect(RABBITMQ_URL);
  const channel = await connection.createChannel();

  const messageBody = JSON.stringify(event);
  const signature = crypto
    .createHmac('sha256', MESSAGE_SIGNING_SECRET)
    .update(messageBody)
    .digest('hex');

  await channel.assertQueue(PAYMENT_QUEUE, { durable: true });
  channel.sendToQueue(PAYMENT_QUEUE, Buffer.from(messageBody), {
    persistent: true,
    headers: { signature },
  });

  console.log('[PUBLISHER] Sent signed payment event:', event.eventId);
  await channel.close();
  await connection.close();
}

// Start consumer
startConsumer();

// Export for testing
